import argparse
import json
import pickle
from pathlib import Path
from collections import defaultdict
import numpy as np
import heapq
import glob
import os
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic", "alpha": 2.0, "beta": 1.5}

def get_env_type(map_path):
    pstr = str(map_path).lower()
    if 'room' in pstr: return 'room'
    if 'tunnel' in pstr: return 'tunnel'
    return 'outdoor'

def coord_to_tuple(c):
    if isinstance(c, np.ndarray): return tuple(np.round(c.astype(float), 6))
    if isinstance(c, (list, tuple)): return tuple(np.round(np.array(c).astype(float), 6))
    return c

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors: return None
    nodes = obs.get("nodes", [])
    if not nodes: return neighbors[0]
    node_dict = {coord_to_tuple(node.get("coords")): node for node in nodes if "coords" in node}
    current_pos = coord_to_tuple(obs.get("robot_pos", np.zeros(2)))
    if current_pos not in node_dict:
        min_d, closest = float('inf'), None
        for nc in node_dict:
            d = np.linalg.norm(np.subtract(nc, current_pos))
            if d < min_d: min_d, closest = d, nc
        if closest is not None: current_pos = closest
    if current_pos not in node_dict:
        best_u, best = -1, neighbors[0]
        for n in neighbors:
            nc = coord_to_tuple(n)
            u = node_dict.get(nc, {}).get("utility", 0)
            if u > best_u: best_u, best = u, n
        return best
    graph = {}
    utilities = {}
    visited = {}
    for coord, node in node_dict.items():
        ns = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = [n for n in ns if n in node_dict]
        utilities[coord] = float(node.get("utility", 0.0))
        visited[coord] = bool(node.get("visited", False))
    def edge_dist(a, b):
        return np.linalg.norm(np.subtract(a, b))
    def dijkstra(start):
        dists = {start: 0.0}
        prev = {start: None}
        pq = [(0.0, start)]
        while pq:
            d, u = heapq.heappop(pq)
            if d > dists.get(u, float('inf')): continue
            for v in graph.get(u, []):
                alt = d + edge_dist(u, v)
                if alt < dists.get(v, float('inf')):
                    dists[v] = alt
                    prev[v] = u
                    heapq.heappush(pq, (alt, v))
        return dists, prev
    all_dists, prev = dijkstra(current_pos)
    alpha = model.get("alpha", 2.0)
    beta = model.get("beta", 1.5)
    best_score = -float('inf')
    best_target = None
    for tcoord, util in utilities.items():
        if util <= 0 or visited.get(tcoord, True): continue
        d = all_dists.get(tcoord, float('inf'))
        if d == float('inf') or d < 0.01: continue
        score = (util ** beta) / (d ** alpha + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord
    if best_target is None:
        best_u = -1.0
        best_n = neighbors[0]
        for n_raw in neighbors:
            nc = coord_to_tuple(n_raw)
            u = utilities.get(nc, 0.0)
            if u > best_u:
                best_u = u
                best_n = n_raw
        return best_n
    curr = best_target
    while prev.get(curr) is not None and prev.get(curr) != current_pos:
        curr = prev.get(curr)
    next_coord = curr
    for neigh in neighbors:
        if coord_to_tuple(neigh) == next_coord:
            return neigh
    best_u = -1.0
    best_n = neighbors[0]
    for n_raw in neighbors:
        nc = coord_to_tuple(n_raw)
        u = utilities.get(nc, 0.0)
        if u > best_u:
            best_u = u
            best_n = n_raw
    return best_n

def run_evaluation(data_path, checkpoint, output_path):
    model = load_model(checkpoint)
    data_path = Path(data_path)
    output_path = Path(output_path)
    output_path.parent.mkdir(parents=True, exist_ok=True)
    maps = []
    config_path = data_path / "eval_config.json"
    if config_path.exists():
        try:
            with open(config_path, "r") as f:
                config = json.load(f)
            for key in ["maps", "map_paths", "map_list", "files", "map_files", "test_maps", "map_paths"]:
                if key in config and isinstance(config[key], list) and config[key]:
                    for m in config[key]:
                        p = Path(m)
                        for base in [data_path, data_path/"maps_eval", data_path/"maps_train", Path("/data")]:
                            cand = base / p.name if not p.is_absolute() else p
                            if cand.exists() and cand.suffix.lower() in ['.png', '.jpg', '.jpeg']:
                                maps.append(cand)
                                break
                    break
        except Exception as e:
            print(f"Config load error: {e}")
    if not maps:
        maps_eval_dir = data_path / "maps_eval"
        if maps_eval_dir.exists() and maps_eval_dir.is_dir():
            for root, dirs, files in os.walk(maps_eval_dir):
                for file in files:
                    if file.lower().endswith(('.png', '.jpg', '.jpeg')):
                        maps.append(Path(root) / file)
    if not maps:
        print("No eval_config.json or maps_eval, using 3 training maps per type for local testing.")
        maps_train_dir = data_path / "maps_train"
        if maps_train_dir.exists():
            for typ in ["room", "tunnel", "outdoor"]:
                typ_dir = maps_train_dir / typ
                if typ_dir.exists():
                    typ_maps = sorted(typ_dir.glob("*.png"))[:3]
                    maps.extend(typ_maps)
    if not maps:
        maps = glob.glob(str(data_path / "**/*.png"), recursive=True)[:9]
    print(f"Evaluating on {len(maps)} maps.")
    results = []
    per_type_counts = {t: {"count": 0, "success_count": 0, "total_explored": 0.0, "total_dist": 0.0} for t in ["room", "tunnel", "outdoor"]}
    for map_path in maps:
        map_path = Path(map_path)
        etype = get_env_type(map_path)
        try:
            env = ExplorationEnv(map_path=str(map_path))
            obs = env.reset()
            for _ in range(128):
                target = select_waypoint(obs, model)
                if target is None:
                    break
                obs, info = env.step(target)
                if info.get("done", False):
                    break
            metrics = env.get_metrics()
            success = 1 if metrics.get("success", metrics.get("explored_rate", 0.0) > 0.9999) else 0
            explored = metrics.get("explored_rate", 0.0)
            dist = metrics.get("travel_distance", 0.0)
            results.append({
                "map_path": str(map_path.name),
                "env_type": etype,
                "success": success,
                "travel_distance": float(dist),
                "explored_rate": float(explored)
            })
            per_type_counts[etype]["count"] += 1
            per_type_counts[etype]["total_explored"] += explored
            if success:
                per_type_counts[etype]["success_count"] += 1
                per_type_counts[etype]["total_dist"] += dist
        except Exception as e:
            print(f"Error on {map_path}: {str(e)}")
            results.append({
                "map_path": str(map_path.name),
                "env_type": etype,
                "success": 0,
                "travel_distance": 0.0,
                "explored_rate": 0.0
            })
            per_type_counts[etype]["count"] += 1
    if not results:
        print("No maps processed.")
        output_dict = {"explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0, "per_episode": [], "per_type": {}, "total_episodes": 0}
        with open(output_path, "w") as f:
            json.dump(output_dict, f, indent=2)
        return
    explored_rate = np.mean([r["explored_rate"] for r in results])
    success_rate = np.mean([r["success"] for r in results])
    successful_dists = [r["travel_distance"] for r in results if r["success"] == 1 and r["travel_distance"] > 0]
    travel_distance = np.mean(successful_dists) if successful_dists else 0.0
    exploration_score = 0.0
    N = len(results)
    for r in results:
        if r["success"] == 1 and r["travel_distance"] > 0:
            exploration_score += 300.0 / r["travel_distance"]
    exploration_score /= N if N > 0 else 1.0
    per_type = {}
    for t in ["room", "tunnel", "outdoor"]:
        c = per_type_counts[t]["count"]
        if c == 0:
            per_type[t] = {"explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0}
            continue
        expl = per_type_counts[t]["total_explored"] / c
        succ_rate = per_type_counts[t]["success_count"] / c
        t_dist = per_type_counts[t]["total_dist"] / per_type_counts[t]["success_count"] if per_type_counts[t]["success_count"] > 0 else 0.0
        per_type[t] = {"explored_rate": float(expl), "travel_distance": float(t_dist), "success_rate": float(succ_rate)}
    output_dict = {
        "explored_rate": float(explored_rate),
        "travel_distance": float(travel_distance),
        "success_rate": float(success_rate),
        "per_episode": results,
        "per_type": per_type,
        "total_episodes": len(results),
        "exploration_score": float(exploration_score)
    }
    with open(output_path, "w") as f:
        json.dump(output_dict, f, indent=2)
    print(f"Evaluation completed with exploration_score proxy based on success and distance.")
    print(f"Success rate: {success_rate:.4f}, Explored: {explored_rate:.4f}, Avg dist: {travel_distance:.2f}")
    print(f"Proxy exploration_score: {exploration_score:.4f}")
    print("Local test on train subset done.")
    print(f"Output written to {output_path}")

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, default="/data")
    parser.add_argument("--checkpoint", type=str, default="checkpoints/baseline")
    parser.add_argument("--output", type=str, default="output.json")
    args = parser.parse_args()
    run_evaluation(args.data_path, args.checkpoint, args.output)

if __name__ == "__main__":
    main()
